import java.util.Random
import java.security.MessageDigest

const val CHARACTERS = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789abcdefghijklmnopqrstuvwxyz"

fun generateSessionId(): String {
    val random = Random()
    val stringBuilder = StringBuilder(32)
    for (i in 0 until 32) {
        stringBuilder.append(CHARACTERS[random.nextInt(CHARACTERS.length)])
